# Category: insecure_coap

import network
import machine
from microcoapy import MicroCoAP
from microcoapy import COAP_CODE_205_CONTENT, COAP_CODE_204_CHANGED, COAP_CODE_400_BAD_REQUEST

# --- Device State Simulation ---
# These variables simulate the state of your IoT device's resources.
# In a real device, these would interact with actual sensors/actuators.
current_temp = 25.5
light_on = False

# --- CoAP Resource Handlers ---

def get_temp_handler(request, response):
    """
    Handles GET requests for the /sensors/temp resource.
    Returns the current simulated temperature.
    """
    global current_temp
    print(f"GET /sensors/temp request from {request.remote_addr}")

    # Simulate temperature fluctuation for demonstration
    # In a real scenario, you'd read from a physical temperature sensor
    current_temp = round(current_temp + (machine.rng() % 50 - 25) / 100.0, 1)

    response.code = COAP_CODE_205_CONTENT  # 2.05 Content
    response.payload = str(current_temp).encode('utf-8')
    response.content_format = 0            # TEXT/PLAIN

def get_light_handler(request, response):
    """
    Handles GET requests for the /actuators/light resource.
    Returns the current simulated light state ('on' or 'off').
    """
    global light_on
    print(f"GET /actuators/light request from {request.remote_addr}")

    response.code = COAP_CODE_205_CONTENT  # 2.05 Content
    response.payload = (b"on" if light_on else b"off")
    response.content_format = 0            # TEXT/PLAIN

def put_light_handler(request, response):
    """
    Handles PUT requests for the /actuators/light resource.
    Updates the simulated light state based on the request payload.
    """
    global light_on
    print(f"PUT /actuators/light request from {request.remote_addr} with payload: {request.payload}")

    if request.payload == b"on":
        light_on = True
        response.code = COAP_CODE_204_CHANGED  # 2.04 Changed
        response.payload = b"Light turned ON."
    elif request.payload == b"off":
        light_on = False
        response.code = COAP_CODE_204_CHANGED  # 2.04 Changed
        response.payload = b"Light turned OFF."
    else:
        response.code = COAP_CODE_400_BAD_REQUEST # 4.00 Bad Request
        response.payload = b"Invalid payload. Use 'on' or 'off'."
    response.content_format = 0             # TEXT/PLAIN

# --- CoAP Server Setup ---

def start_coap_server():
    """
    Initializes and starts the MicroCoAP server, registering resource handlers.
    """
    server = MicroCoAP()

    # Register resources:
    # Path should be bytes.
    # The handler functions are passed as arguments for GET, PUT, POST, DELETE.

    # /sensors/temp: Supports GET only
    server.add_resource(b"sensors/temp", get_temp_handler)

    # /actuators/light: Supports GET and PUT
    server.add_resource(b"actuators/light", get_light_handler, callback_put=put_light_handler)

    print("CoAP server started. Waiting for requests...")
    while True:
        # The loop method processes incoming CoAP packets.
        # It's important to call this regularly to keep the server responsive.
        server.loop(100) # Poll for CoAP packets every 100ms
        # You can add other device-specific tasks here that need to run
        # periodically alongside the CoAP server.

# --- Network Setup ---

def connect_wifi(ssid, password):
    """
    Connects the device to a Wi-Fi network.
    """
    print("Connecting to WiFi...")
    sta_if = network.WLAN(network.STA_IF)
    sta_if.active(True)
    sta_if.connect(ssid, password)

    max_attempts = 20 # Roughly 10 seconds timeout
    attempts = 0
    while not sta_if.isconnected() and attempts < max_attempts:
        print(".", end="")
        machine.idle() # Yield CPU to other tasks while waiting
        attempts += 1
    print()

    if sta_if.isconnected():
        print("WiFi connected:", sta_if.ifconfig())
    else:
        print("Failed to connect to WiFi.")
    return sta_if.isconnected()

# --- Main Execution ---

if __name__ == "__main__":
    # --- Configuration ---
    WIFI_SSID = "YOUR_WIFI_SSID"      # <--- IMPORTANT: Replace with your Wi-Fi SSID
    WIFI_PASSWORD = "YOUR_WIFI_PASSWORD"  # <--- IMPORTANT: Replace with your Wi-Fi password

    if connect_wifi(WIFI_SSID, WIFI_PASSWORD):
        start_coap_server()
    else:
        print("CoAP server cannot start without a network connection.")
        print("Please check your WiFi credentials and network availability.")

